// Dedup check - prevent duplicate notifications within 10 minutes
const email = $input.first().json.body?.email || $input.first().json.email || 'unknown';
const eventType = 'early-access';
const key = 'dedup_' + eventType + '_' + email.toLowerCase().replace(/[^a-z0-9]/g,'');
const now = Date.now();
const ttl = 10 * 60 * 1000; // 10 minutes

const stored = $getWorkflowStaticData('global');
if (!stored.dedup) stored.dedup = {};

// Clean expired entries
for (const k of Object.keys(stored.dedup)) {
  if (now - stored.dedup[k] > ttl) {
    delete stored.dedup[k];
  }
}

if (stored.dedup[key]) {
  // Duplicate within TTL - stop execution
  return [];
}

// Mark as seen
stored.dedup[key] = now;
return $input.all();

const rawData = $input.item.json;
const data = rawData.body || rawData;

const name = data.name || 'N/A';
const email = data.email || 'N/A';
const message = data.message || '';
const source = data.source || 'The Print Route';
const ts = new Date().toLocaleString('sv-SE', { timeZone: 'Europe/Stockholm' });

const text = `\u{1F3AF} <b>Ny kontaktförfrågan – ${source}</b>\n\n<b>Namn:</b> ${name}\n<b>E-post:</b> ${email}` + (message ? `\n<b>Meddelande:</b> ${message}` : '') + `\n<b>Källa:</b> ${source}\n<b>Tid:</b> ${ts}`;

const token = '8683132686:AAF5yJ206OcLKsSBx0n4Nm4uBAxcQlRbwyc';
const chatId = '-1003767033253';

try {
  const response = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' })
  });
  return [{ json: { success: response.ok } }];
} catch (e) {
  return [{ json: { success: false } }];
}

// Format the message for Slack
// n8n webhook puts JSON body in body property or directly in root
const rawData = $input.item.json;
const data = rawData.body || rawData;

const slackMessage = {
  text: `🎯 *New Early Access Request*\n\n` +
        `*Name:* ${data.name || 'Not provided'}\n` +
        `*Email:* ${data.email || 'Not provided'}\n` +
        `*Message:*\n${data.message || 'No message provided'}\n\n` +
        `*Timestamp:* ${data.timestamp || new Date().toISOString()}\n` +
        `*Source:* ${data.source || 'Unknown'}`,
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: '🎯 New Early Access Request'
      }
    },
    {
      type: 'section',
      fields: [
        {
          type: 'mrkdwn',
          text: `*Name:*\n${data.name || 'Not provided'}`
        },
        {
          type: 'mrkdwn',
          text: `*Email:*\n${data.email || 'Not provided'}`
        }
      ]
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Message:*\n${data.message || 'No message provided'}`
      }
    },
    {
      type: 'context',
      elements: [
        {
          type: 'mrkdwn',
          text: `📅 ${data.timestamp || new Date().toISOString()} | 🔗 ${data.source || 'Unknown'}`
        }
      ]
    }
  ]
};

return { json: slackMessage };
